INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('20-dental-os-flywheel',2,20,'THE DENTAL OS FLYWHEEL ENGINE','Dong co banh xe Dental Empire OS',20,'draft','2026-06-20T15:24:19Z','2026-06-20T15:24:19Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e5195e0c-c110-408a-84a5-1023d848e253','20-dental-os-flywheel',NULL,2,'20.1 Lớp nào nuôi lớp nào? Bản đồ dòng chảy năng lượng hệ thống','201-lop-nao-nuoi-lop-nao-ban-o-dong-chay-nang-luong-he-thong',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d2fc5c0d-fc12-4472-a965-f25a15e58128','e5195e0c-c110-408a-84a5-1023d848e253',0,'text','Trong tư duy quản trị nha khoa cũ, các hoạt động kinh doanh vận hành giống như một đường thẳng tuyến tính: Đốt tiền chạy Ads ➔ Có khách đến ➔ Điều trị xong ➔ Hết dòng tiền. Mô hình này khiến phòng khám RHM luôn rơi vào trạng thái "nghiện quảng cáo" và cực kỳ tổn thương trước áp lực tăng giá chi phí hiển thị (CAC).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8d6ee063-870b-46ce-ba46-445afd3f9b3a','e5195e0c-c110-408a-84a5-1023d848e253',1,'text','Hệ điều hành **Dental Empire OS** phá vỡ hoàn toàn tư duy này bằng cách thiết lập một **Bánh đà tăng trưởng vĩnh cửu (Flywheel Engine)**. Hệ thống không dựa vào dòng máu tiêm từ bên ngoài, mà tự sản sinh năng lượng thông qua một vòng lặp phản hồi dương khép kín. Mỗi một phân tầng khi vận hành xuất sắc sẽ tự động sinh ra tài sản để làm bệ phóng nuôi dưỡng phân tầng tiếp theo, tạo thành một phương trình toán học quản trị bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1214075a-1088-4e2f-b57b-e03afc4b251f','e5195e0c-c110-408a-84a5-1023d848e253',2,'text','Để vận hành bánh đà này trên thực địa, nhà quản trị bắt buộc phải thấu hiểu bản chất dòng chảy chuyển hóa giá trị. Năng lượng của hệ thống nha khoa **Thích Làm Răng** được lập trình luân chuyển nghiêm ngặt theo chuỗi liên kết 7 chương dưới đây:',NULL,NULL,NULL,NULL,NULL);
