INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a59c70f2-a224-4699-a03b-f5464093d400','e5195e0c-c110-408a-84a5-1023d848e253',7,'text','Sự phân phối nội dung giáo dục thường thức đều đặn bẻ gãy mọi sự hoài nghi, sưởi ấm nhận thức và tạo lập niềm tin tuyệt đối.',NULL,NULL,NULL,NULL,NULL);
