INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb731f62-1849-4405-b52b-da3fb30daeb9','e5195e0c-c110-408a-84a5-1023d848e253',9,'text','Khi niềm tin chạm đỉnh, khách hàng chủ động bước vào đường ống hành trình (đặt lịch, đến khám) với tỷ lệ ma sát tâm lý bằng 0.',NULL,NULL,NULL,NULL,NULL);
