INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a6de797e-65b7-47b8-8478-162b39a0dc91','e5195e0c-c110-408a-84a5-1023d848e253',11,'text','Một hành trình được thiết kế chuẩn chỉnh, đúng tiến độ thiết lập sẵn một bệ phóng hoàn hảo cho trải nghiệm lâm sàng thực tế tại ghế nha.',NULL,NULL,NULL,NULL,NULL);
