INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f369d98-5b4b-48fb-9866-be37dbe9a0a9','e5195e0c-c110-408a-84a5-1023d848e253',13,'text','Kết quả điều trị xuất sắc kết hợp hiệu ứng Wow Peak về dịch vụ kích nổ phản xạ truyền miệng và giới thiệu tự nhiên của bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
