INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('77fe2d4f-0a3b-4fa2-91ec-043debd56941','e5195e0c-c110-408a-84a5-1023d848e253',15,'text','Nguồn khách giới thiệu chất lượng cao là chất liệu hoàn hảo nhất để thu nạp vào các chương trình Membership và tiểu cộng đồng thân thiết.',NULL,NULL,NULL,NULL,NULL);
