INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e01c5f81-c3b1-446a-b55d-0a3739ac6a5b','e5195e0c-c110-408a-84a5-1023d848e253',17,'text','Sức sống, bài đánh giá (Review) và câu chuyện thành công của cộng đồng quay ngược trở lại củng cố, nâng cấp vị thế tối cao cho Thương hiệu gốc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('322c1907-7e58-4396-a606-9eb3743b7d66','20-dental-os-flywheel','e5195e0c-c110-408a-84a5-1023d848e253',3,'Brand nuôi Media: linh hồn và tiêu chuẩn nội dung','brand-nuoi-media-linh-hon-va-tieu-chuan-noi-dung',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9935d530-7762-4a20-98bb-a0f15ea66868','322c1907-7e58-4396-a606-9eb3743b7d66',18,'text','Nhiều phòng khám nha khoa hiện nay có kênh truyền thông nhưng không có bản sắc, nội dung xơ cứng vì thiếu đi cái "gốc" định vị. **Brand (Thương hiệu/Uy tín Bác sĩ)** chính là nhà máy sản xuất nhiên liệu cho toàn bộ hệ thống **Media Network**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3e0bfd64-7648-4d88-b314-1bd3ed367dcf','322c1907-7e58-4396-a606-9eb3743b7d66',19,'text','- **Chất liệu thực tế:** Uy tín chuyên gia của Bác sĩ Nguyễn Phước Vinh, các ca lâm sàng thành công rực rỡ và triết lý y đức tử tế của phòng khám là nguồn chất liệu sạch, độc quyền mà không đối thủ nào có thể sao chép được.- **Vận hành:** Thương hiệu định hình tiêu chuẩn phát ngôn, màu sắc nhận diện và tông giọng (Tone of Voice) cho Media. Brand giúp Media không rơi vào cái bẫy giật gân, rẻ tiền, mà luôn giữ vững tính chuyên nghiệp, đẳng cấp của một tổ chức y khoa thượng lưu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b6c52328-7e38-490f-b15b-b77fccfa1681','20-dental-os-flywheel','e5195e0c-c110-408a-84a5-1023d848e253',3,'Media nuôi Trust: số hóa sự thấu cảm, khơi thông niềm tin','media-nuoi-trust-so-hoa-su-thau-cam-khoi-thong-niem-tin',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c2dcf32f-1023-4ab9-83cd-1f563d421785','b6c52328-7e38-490f-b15b-b77fccfa1681',20,'text','Khách hàng không bao giờ tin tưởng một phòng khám xa lạ ngay từ cái nhìn đầu tiên, đặc biệt là với các dịch vụ can thiệp sâu, chi phí lớn như Implant hay Chỉnh nha. **Media (Mạng lưới truyền thông)** chính là công cụ để số hóa lòng tin trên diện rộng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d12fb7db-a8bf-4262-a72d-46a13cfd4fe7','b6c52328-7e38-490f-b15b-b77fccfa1681',21,'text','- **Giáo dục nhận thức:** Thông qua các chuỗi video ngắn trên TikTok, các bài viết phân tích case chuyên sâu trên website, Media liên tục giải đáp các nỗi sợ hãi, bóc tách các lỗi chăm sóc sai lầm hằng ngày của khách hàng.- **Vận hành:** Khi Media xuất hiện đều đặn với tư cách là một người chia sẻ giá trị tử tế, bộ lọc hoài nghi của thị trường tự động bị vô hiệu hóa. Sự lặp đi lặp lại của nội dung chất lượng cao chuyển hóa người xem từ trạng thái tò mò sang trạng thái **Trust (Niềm tin tuyệt đối vào năng lực chuyên gia)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d48659e2-0091-4f33-ad70-e666267a13f9','20-dental-os-flywheel','e5195e0c-c110-408a-84a5-1023d848e253',3,'Trust nuôi Journey: phá bỏ ma sát để điều hướng đường ống','trust-nuoi-journey-pha-bo-ma-sat-e-ieu-huong-uong-ong',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('64d2df9f-26fd-4c77-a0c7-407986d6ed60','d48659e2-0091-4f33-ad70-e666267a13f9',22,'text','Khi một phòng khám cố gắng chèo kéo khách hàng khi họ chưa có niềm tin, tỷ lệ rơi rụng (Drop Rate) trên đường ống sẽ cực kỳ cao. Nhưng một khi **Trust (Niềm tin)** đã được thiết lập vững chắc qua hệ thống giáo dục, việc đưa khách hàng vào **Journey (Hành trình bệnh nhân)** trở nên vô cùng mượt mà:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('625186a9-5c85-419e-b85b-a9da460e73bc','d48659e2-0091-4f33-ad70-e666267a13f9',23,'text','- **Tự động chuyển đổi:** Khách hàng chủ động để lại thông tin, tự quét mã QR đặt lịch hẹn, thong thả đến phòng khám theo đúng kịch bản thiết lập sẵn mà không cần đội ngũ Sales phải dùng các thủ thuật giục giã, ép uổng.- **Vận hành:** Niềm tin chạm đỉnh giúp triệt tiêu 100% rào cản về giá và rào cản sợ đau sinh học, đưa bệnh nhân bước vào hành trình một cách tự nguyện, sẵn sàng hợp tác chặt chẽ với phác đồ điều trị của Bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('989a3a94-cb56-47cc-be9e-021580aca543','20-dental-os-flywheel','e5195e0c-c110-408a-84a5-1023d848e253',3,'Customer Journey nuôi Experience: thiết lập tâm thế trước ghế điều trị','customer-journey-nuoi-experience-thiet-lap-tam-the-truoc-ghe-ieu-tri',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b704b966-b965-4c19-92b8-b1a43099d0df','989a3a94-cb56-47cc-be9e-021580aca543',24,'text','Một trải nghiệm lâm sàng tại ghế nha (*Clinic OS*) có thành công hay không phụ thuộc rất lớn vào trạng thái tâm lý của bệnh nhân trước khi bước vào phòng điều trị. **Journey (Thiết kế hành trình)** chính là cấu phần chuẩn bị tâm thế xuất sắc cho **Experience (Trải nghiệm thực địa)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('26b3e23c-3271-4d16-97de-3f67129dec17','989a3a94-cb56-47cc-be9e-021580aca543',25,'text','- **Đúng kỳ vọng:** Nhờ các điểm chạm truyền thông dặn dò trước khi đến khám (File 202), bệnh nhân đã biết rõ quy trình, hiểu rõ cảm giác sinh học sắp diễn ra, loại bỏ hoàn toàn sự hoang mang, hoảng sợ bộc phát.- **Vận hành:** Hành trình tiếp đón đồng bộ từ bãi giữ xe, quầy lễ tân đến sảnh chờ được vận hành mượt mà tạo cho bệnh nhân một cảm giác an toàn tuyệt đối. Khi bước lên ghế điều trị, họ ở trạng thái tâm lý thả lỏng nhất, giúp Bác sĩ thực thi thủ thuật lâm sàng đạt độ chính xác và an toàn tối đa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('eb395b6e-baa4-4308-8905-baad13c2fc74','20-dental-os-flywheel','e5195e0c-c110-408a-84a5-1023d848e253',3,'Experience nuôi Referral: kích nổ phản xạ truyền miệng tự nhiên','experience-nuoi-referral-kich-no-phan-xa-truyen-mieng-tu-nhien',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('84354c9f-055b-41f1-8360-80e0bc070920','eb395b6e-baa4-4308-8905-baad13c2fc74',26,'text','Bệnh nhân không đi giới thiệu phòng khám của bạn chỉ vì bạn xin họ, họ chỉ giới thiệu khi trải nghiệm của họ đạt mức độ **Wow Peak (Vượt ngoài mong đợi)**. **Experience (Trải nghiệm thực tế)** chính là ngòi nổ tối cao kích hoạt hệ sinh thái **Referral**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ad54bef6-0d48-4995-ae45-92c773e7536c','eb395b6e-baa4-4308-8905-baad13c2fc74',27,'text','- **Sự tự hào chia sẻ:** Khi kết quả điều trị lâm sàng hoàn hảo (răng hết ê buốt, nụ cười sứ thanh tú tự nhiên) kết hợp với sự chăm sóc tinh tế của đội phụ tá, lòng biết ơn của bệnh nhân sẽ biến thành hành động.- **Vận hành:** Giới thiệu người thân lúc này không còn là một nghĩa vụ, mà là một phản xạ tự nhiên của sự tự hào: *"Tôi đã làm răng ở Thích Làm Răng, trải nghiệm đẳng cấp và không đau một chút nào, anh/chị nhất định phải qua đó"*. Dòng khách giới thiệu chất lượng cao chính thức được khai thông.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5f8f5da2-edda-419a-8899-56ebec9f7410','20-dental-os-flywheel','e5195e0c-c110-408a-84a5-1023d848e253',3,'Referral nuôi Community: nạp vật liệu sạch vào cộng đồng','referral-nuoi-community-nap-vat-lieu-sach-vao-cong-ong',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('91f36304-d33f-47b0-9d7d-4c9b8d8fc2f8','5f8f5da2-edda-419a-8899-56ebec9f7410',28,'text','Để xây dựng một cộng đồng bền vững, bạn cần những thành viên có độ gắn kết cao và chung một hệ giá trị. Khách hàng đến từ nguồn quảng cáo giảm giá thường chỉ quan tâm đến chi phí và rất dễ rời đi. Nhưng nguồn khách đến từ **Referral (Khách giới thiệu)** lại là nguồn vật liệu sạch tuyệt vời để nuôi dưỡng **Community (Cộng đồng/Membership)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('80596572-ddf3-4a14-b54c-e923cdef9c58','5f8f5da2-edda-419a-8899-56ebec9f7410',29,'text','- **Sẵn có gen trung thành:** Khách giới thiệu vốn dĩ đã được "sưởi ấm" lòng tin thông qua trải nghiệm của người thân họ. Khi hoàn tất điều trị, họ là những ứng viên xuất sắc nhất để nâng cấp lên các gói thẻ hội viên VIP trả trước (*Membership Plan*) và gia nhập vào các nhóm tiểu cộng đồng chuyên biệt.- **Vận hành:** Tệp khách này nhanh chóng hòa nhập vào văn hóa cộng đồng, chủ động tương tác trong các buổi workshop, tạo nên sức sống nội sinh mạnh mẽ cho bộ tộc nụ cười của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('53973622-34aa-42cb-b5f5-acd4a0d33292','20-dental-os-flywheel','e5195e0c-c110-408a-84a5-1023d848e253',3,'Community nuôi Brand: hoàn thành vòng lặp, nâng tầm đế chế','community-nuoi-brand-hoan-thanh-vong-lap-nang-tam-e-che',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a51e7b25-0124-418e-8830-14b3f6ed8002','53973622-34aa-42cb-b5f5-acd4a0d33292',30,'text','Đây là điểm chạm tối thượng đóng lại vòng lặp và đưa hệ thống bước vào chu kỳ tăng trưởng mới ở tầng cấp cao hơn. **Community (Cộng đồng)** quay trở lại tiếp máu, nâng cấp toàn diện cho sức mạnh của **Brand (Thương hiệu gốc)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b719317-44bb-4d21-8fed-073f572b93d4','53973622-34aa-42cb-b5f5-acd4a0d33292',31,'text','- **Bằng chứng thép (Social Proof) tối cao:** Một thương hiệu tự nói về mình thì không ai tin, nhưng một cộng đồng hàng ngàn bệnh nhân cùng lên tiếng bảo vệ, cùng unboxing sản phẩm Homecare, cùng để lại hàng trăm review 5 sao trên Google Maps và tích cực chia sẻ Case Study lột xác — đó là một pháo đài uy tín bất khả xâm phạm.- **Tái định vị vị thế:** Sức mạnh của cộng đồng đẩy thương hiệu của phòng khám thoát khỏi định vị của một phòng mạch tư nhân nhỏ lẻ, chính thức xác lập vị thế của một **Đế chế nha khoa tử tế, có chiều sâu tri thức và sở hữu tệp khách hàng trung thành bền vững trọn đời**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8984815-cf1d-4b14-b507-0dc7245fd77d','53973622-34aa-42cb-b5f5-acd4a0d33292',32,'text','**Mantra tối thượng của Bánh đà Flywheel:***"Đừng vận hành nha khoa như những mảnh ghép rời rạc. Hãy kết nối chúng thành một đường ống năng lượng khép kín, nơi lòng biết ơn của bệnh nhân cũ trở thành niềm tin của bệnh nhân mới, giữ cho bộ máy phòng khám luôn tự động tăng trưởng hưng thịnh và trường tồn trước mọi biến động của thị trường."*',NULL,NULL,NULL,NULL,NULL);
